const body = $input.first().json.body ?? $input.first().json;

const scoreId = body.score_id;
const overallScore = body.overall_score ?? 0;
const totalPassed = body.total_passed ?? 0;
const totalFailed = body.total_failed ?? 0;
const results = body.results ?? [];

const dimLines = results.map(r => {
  const pct = Math.round(r.score);
  const failInfo = r.failed_count > 0
    ? ` - ${r.failed_count} failed rows`
    : ' - all passed';
  const reasons = (r.sample_reasons ?? []).filter(Boolean).slice(0, 3);
  const reasonStr = reasons.length > 0 ? ` (reasons: ${reasons.join('; ')})` : '';
  return `  - ${r.column_name} [${r.dimension}]: ${pct}%${failInfo}${reasonStr}`;
}).join('\n');

const chatInput = `You are a data quality analyst. Analyze the following quality check results and write a brief, professional summary.

Overall Score: ${Math.round(overallScore)}%
Total Checks: ${totalPassed + totalFailed} (${totalPassed} passed, ${totalFailed} failed)

Per-column results:
${dimLines}

Write your response in exactly this format - no extra text, no markdown:

[OVERVIEW]
2-3 sentences summarising the overall quality, which dimensions performed well, and which are concerning.

[KEY ISSUES]
List only columns with failed rows, one per line. Format each as: column_name - dimension - N failed rows - brief reason

[RECOMMENDATIONS]
List 2-3 numbered actionable recommendations based on the results.`;

return [{ json: { score_id: scoreId, chatInput } }];

// AI Agent node outputs { output: "..." }
const agentOutput = $input.first().json.output ?? $input.first().json.text ?? '';
const prevData = $('Build Prompt').first().json;

// Strip any markdown code fences Ollama sometimes adds
const summary = agentOutput
  .replace(/^```[\w]*\n?/gm, '')
  .replace(/```$/gm, '')
  .trim();

return [{ json: { score_id: prevData.score_id, summary } }];
